.feeds-filter {
  background-color: white;
  font-size: 12px;
  width: 100%;
  border-radius: 4px;
  box-sizing: border-box;
  display: none;
  flex-direction: column;
  max-height: 80vh;
  overflow: auto;
  scrollbar-width: none !important;
  overscroll-behavior: contain;
}
.feeds-filter::-webkit-scrollbar {
  height: 0 !important;
  width: 0 !important;
}
body.enable-feeds-filter:not(.disable-feeds-filter) .feeds-filter {
  display: flex;
}
.feeds-filter, .feeds-filter * {
  transition: 0.2s ease-out;
  transition-property: border-color, color, background-color;
}
.feeds-filter > * {
  padding-left: 16px;
  padding-right: 16px;
}
.feeds-filter > *:first-child {
  padding-top: 12px;
}
.feeds-filter > *:last-child {
  padding-bottom: 12px;
}
body.dark .feeds-filter {
  color: var(--be-color-text-title, #eee);
  background-color: var(--be-color-panel-bg, #444);
}
.feeds-filter .feeds-filter-header {
  cursor: pointer;
  padding-bottom: 14px;
  position: sticky;
  top: 0;
  background-color: inherit;
  display: flex;
  align-items: center;
  justify-content: space-between;
}
.feeds-filter .feeds-filter-header h1 {
  font-weight: normal;
  font-size: 14px;
  margin: 0;
}
.feeds-filter.collapse .feeds-filter-header {
  padding-bottom: 12px;
}
.feeds-filter.collapse .feeds-filter-header .be-icon {
  transform: rotate(180deg);
}
.feeds-filter.collapse > :not(.feeds-filter-header) {
  display: none;
}
.feeds-filter.contents-only {
  overflow: visible;
}
.feeds-filter.contents-only > * {
  padding-left: 0;
  padding-right: 0;
}
.feeds-filter h2 {
  font-weight: 600;
  font-size: 13px;
  margin: 0;
  margin-bottom: 8px;
}
.feeds-filter .filter-type-switch {
  flex: 0 0 49%;
}
.feeds-filter .filter-side-card-switch {
  flex: 0 0 100%;
}
.feeds-filter .filter-types {
  display: flex;
  flex-wrap: wrap;
  justify-content: space-between;
  margin-bottom: 18px;
}
body.by-type .feeds-filter h2:nth-of-type(1),
body.by-type .feeds-filter .filter-types {
  display: none;
}
.feeds-filter .filter-patterns:not(:empty) {
  margin-bottom: 4px;
}
.feeds-filter .filter-patterns .pattern {
  display: flex;
  justify-content: space-between;
  position: relative;
  font-size: 12px;
}
.feeds-filter .filter-patterns .pattern:not(:last-child) {
  margin-bottom: 5px;
}
.feeds-filter .filter-patterns .pattern .be-icon {
  padding: 4px;
  cursor: pointer;
}
.feeds-filter .filter-patterns .pattern-actions {
  position: absolute;
  top: 50%;
  transform: translateY(-50%);
  right: 4px;
  display: flex;
  align-items: center;
}
.feeds-filter .filter-patterns .pattern .be-textbox {
  padding-right: 52px;
}
.feeds-filter .filter-patterns .pattern-disabled .be-textbox {
  opacity: 0.5;
}
.feeds-filter .add-pattern {
  display: flex;
  align-items: center;
  margin-bottom: 18px;
}
.feeds-filter .add-pattern input {
  font-size: 12px;
}
.feeds-filter .add-pattern .be-button {
  margin-left: 6px;
  padding: 4px 6px;
